// Parse the Config tab into a creator URL list.
// The Config tab is key/value: column A = key, column B = value.
// We pick out linkedin_creators (newline-separated URLs) and
// linkedin_posts_per_creator (integer, default 5).
const rows = items.map(i => i.json);
const config = {};
for (const r of rows) {
  const key = r.key || r.A;
  const val = r.value !== undefined ? r.value : r.B;
  if (key) config[key] = val == null ? '' : String(val);
}
const raw = config['linkedin_creators'] || '';
const perCreator = parseInt(config['linkedin_posts_per_creator'] || '5', 10);
const urls = raw
  .split('\n')
  .map(s => s.trim())
  .filter(s => s.length > 0 && s.startsWith('http'));
if (urls.length === 0) {
  throw new Error('linkedin_creators is empty in the linkedin-hq Config tab. Add LinkedIn profile URLs (one per line) to row B for the linkedin_creators key.');
}
return [
  {
    json: {
      targetUrls: urls,
      maxPosts: perCreator,
    },
  },
];

// Map raw Apify items into the shape /api/intel/ingest expects.
// The actor returns one item per scraped LinkedIn post with this rough shape:
//   { id, linkedinUrl (post URL), content, author: {linkedinUrl, name},
//     postedAt: {date}, engagement: {likes, comments}, postImages: [...] }
// We flatten into the IntelRow contract on the linkedin-hq side.
const raw = $input.first().json.items || [];
const out = [];
for (const p of raw) {
  if (!p) continue;
  const url = p.linkedinUrl || p.postUrl || p.url || '';
  const text = p.content || p.text || '';
  if (!url || !text) continue;
  const author = p.author || {};
  const engagement = p.engagement || {};
  const postedAt = p.postedAt || {};
  out.push({
    creator_url: author.linkedinUrl || '',
    creator_name: author.name || 'linkedin',
    posted_at: postedAt.date || postedAt || '',
    url,
    text,
    reactions: Number(engagement.likes || 0),
    comments: Number(engagement.comments || 0),
    type: 'linkedin',
  });
}
return [{ json: { items: out } }];
